  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL_ATLAS\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// ══════════════════════════════════════════\n// GROUPS\n// ══════════════════════════════════════════\n\nmodel Group {\n  id              String   @id @default(uuid())\n  name            String   @unique // \"Growth\", \"Retention\"\n  slug            String   @unique // \"growth\", \"retention\"\n  description     String // What tables/data this gives access to\n  icon            String? // Lucide icon name\n  color           String? // Hex color for card\n  externalGroupId String?  @map(\"external_group_id\") // Redash group ID\n  isActive        Boolean  @default(true) @map(\"is_active\")\n  createdAt       DateTime @default(now()) @map(\"created_at\")\n  updatedAt       DateTime @updatedAt @map(\"updated_at\")\n  tables          String[]\n  platform        Platform @default(REDASH)\n\n  admins         GroupAdmin[]\n  accessRequests AccessRequest[]\n  userAccesses   UserAccess[]\n\n  @@map(\"groups\")\n}\n\nmodel GroupAdmin {\n  id         String   @id @default(uuid())\n  groupId    String   @map(\"group_id\")\n  userId     String   @map(\"user_id\") // Keycloak user ID\n  userName   String   @map(\"user_name\")\n  userEmail  String   @map(\"user_email\")\n  assignedAt DateTime @default(now()) @map(\"assigned_at\")\n  assignedBy String   @map(\"assigned_by\")\n\n  group Group @relation(fields: [groupId], references: [id], onDelete: Cascade)\n\n  @@unique([groupId, userId])\n  @@map(\"group_admins\")\n}\n\n// ══════════════════════════════════════════\n// ACCESS REQUESTS\n// ══════════════════════════════════════════\n\nmodel AccessRequest {\n  id      String @id @default(uuid())\n  groupId String @map(\"group_id\")\n\n  // Requester (from Keycloak token)\n  requesterId    String @map(\"requester_id\")\n  requesterName  String @map(\"requester_name\")\n  requesterEmail String @map(\"requester_email\")\n\n  // Request\n  justification String\n  duration      AccessDuration @default(PERMANENT)\n  expiresAt     DateTime?      @map(\"expires_at\")\n\n  // Review\n  status       RequestStatus @default(PENDING)\n  reviewerId   String?       @map(\"reviewer_id\")\n  reviewerName String?       @map(\"reviewer_name\")\n  reviewNote   String?       @map(\"review_note\")\n  reviewedAt   DateTime?     @map(\"reviewed_at\")\n\n  // Provisioning\n  provisionedAt  DateTime? @map(\"provisioned_at\")\n  provisionError String?   @map(\"provision_error\")\n  revokedAt      DateTime? @map(\"revoked_at\")\n  revokeReason   String?   @map(\"revoke_reason\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  group        Group        @relation(fields: [groupId], references: [id])\n  auditEntries AuditEntry[]\n\n  @@index([requesterId])\n  @@index([status])\n  @@index([groupId, status])\n  @@index([expiresAt])\n  @@map(\"access_requests\")\n}\n\n// ══════════════════════════════════════════\n// USER ACCESS (source of truth)\n// ══════════════════════════════════════════\n\nmodel UserAccess {\n  id             String  @id @default(uuid())\n  userId         String  @map(\"user_id\")\n  userName       String  @map(\"user_name\")\n  userEmail      String  @map(\"user_email\")\n  groupId        String  @map(\"group_id\")\n  externalUserId String? @map(\"external_user_id\") // Redash user ID\n\n  isActive  Boolean   @default(true) @map(\"is_active\")\n  grantedAt DateTime  @default(now()) @map(\"granted_at\")\n  expiresAt DateTime? @map(\"expires_at\")\n  revokedAt DateTime? @map(\"revoked_at\")\n\n  grantedBy       String  @map(\"granted_by\")\n  accessRequestId String? @map(\"access_request_id\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  group Group @relation(fields: [groupId], references: [id])\n\n  // Removed: @@unique([userId, groupId, isActive])\n  // This caused violations on repeated grant/revoke cycles.\n  // Uniqueness for active access is now enforced via application logic\n  // and a unique index on (userId, groupId) WHERE isActive = true.\n  @@index([expiresAt, isActive])\n  @@map(\"user_accesses\")\n}\n\n// ══════════════════════════════════════════\n// NOTIFICATIONS (in-app)\n// ══════════════════════════════════════════\n\nmodel Notification {\n  id        String   @id @default(uuid())\n  userId    String   @map(\"user_id\")\n  title     String\n  message   String\n  linkUrl   String?  @map(\"link_url\")\n  isRead    Boolean  @default(false) @map(\"is_read\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@index([userId, isRead])\n  @@map(\"notifications\")\n}\n\n// ══════════════════════════════════════════\n// AUDIT LOG\n// ══════════════════════════════════════════\n\nmodel AuditEntry {\n  id              String   @id @default(uuid())\n  action          String // \"REQUEST_CREATED\", \"APPROVED\", etc.\n  performerId     String   @map(\"performer_id\")\n  performerName   String   @map(\"performer_name\")\n  targetUserId    String?  @map(\"target_user_id\")\n  targetUserName  String?  @map(\"target_user_name\")\n  groupId         String?  @map(\"group_id\")\n  accessRequestId String?  @map(\"access_request_id\")\n  details         Json?\n  ipAddress       String?  @map(\"ip_address\")\n  createdAt       DateTime @default(now()) @map(\"created_at\")\n\n  accessRequest AccessRequest? @relation(fields: [accessRequestId], references: [id])\n\n  @@index([performerId])\n  @@index([action])\n  @@index([createdAt])\n  @@map(\"audit_entries\")\n}\n\n// ══════════════════════════════════════════\n// REDASH CACHE (synced from Redash on setup)\n// ══════════════════════════════════════════\n\nmodel RedashUser {\n  id           Int      @id\n  name         String\n  email        String   @unique\n  isDisabled   Boolean  @default(false) @map(\"is_disabled\")\n  groupIds     Int[]    @map(\"group_ids\")\n  lastSyncedAt DateTime @map(\"last_synced_at\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"redash_users\")\n}\n\nmodel RedashGroup {\n  id           Int      @id\n  name         String\n  type         String\n  memberCount  Int      @default(0) @map(\"member_count\")\n  lastSyncedAt DateTime @map(\"last_synced_at\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"redash_groups\")\n}\n\n// ══════════════════════════════════════════\n// ENUMS\n// ══════════════════════════════════════════\n\nenum AccessDuration {\n  ONE_DAY\n  ONE_WEEK\n  ONE_MONTH\n  THREE_MONTHS\n  PERMANENT\n}\n\nenum RequestStatus {\n  PENDING\n  APPROVED\n  REJECTED\n  PROVISIONING\n  PROVISIONED\n  PROVISION_FAILED\n  EXPIRED\n  REVOKED\n}\n\nenum Platform {\n  REDASH\n  // Future: AWS, JIRA, GITHUB, etc.\n}\n",
